use strict;
use warnings;
use PDF::API2;
use PDF::Text::Simple;

# Function to extract text from a PDF
sub extract_text {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);
    my $pages = $pdf->pages;
    my @text = ();

    for (my $i = 1; $i <= $pages; $i++) {
        my $page = $pdf->page($i);
        my $text = $page->extract_text();
        push @text, $text;
    }

    return join("\n", @text);
}

